"""konkon plugin — konkon db 実装用コンテキスト.

build() は BUILDS 宣言に従いストアにデータを書き込む。
query() は QUERIES 宣言に従いストアからレスポンスを組み立てる。
両者は store_path だけで接続される。

Context Store: context.json (plugin dir)
"""

import json
import sys
from concurrent.futures import ThreadPoolExecutor, as_completed
from pathlib import Path

from konkon.types import RawDataAccessor, QueryRequest, QueryResult

import llm
from targets import BUILDS, QUERIES

MAX_WORKERS = 4

# ---------------------------------------------------------------------------
# Constants
# ---------------------------------------------------------------------------

PLUGIN_DIR = Path(__file__).parent
CONTEXT_FILE = PLUGIN_DIR / "context.json"
CACHE_FILE = PLUGIN_DIR / "llm_cache.json"

# ---------------------------------------------------------------------------
# Store helpers
# ---------------------------------------------------------------------------


def _load_store() -> dict:
    if CONTEXT_FILE.exists():
        return json.loads(CONTEXT_FILE.read_text())
    return {"version": 1, "views": {}, "tables": {}}


def _save_store(store: dict) -> None:
    CONTEXT_FILE.write_text(json.dumps(store, ensure_ascii=False, indent=2) + "\n")


def _store_get(store: dict, path: str):
    """store_path (e.g. 'views.implementation.l0') からネストした値を取得."""
    node = store
    for key in path.split("."):
        node = node.get(key, {})
    return node


def _store_set(store: dict, path: str, value) -> None:
    """store_path (e.g. 'views.implementation.l0') にネストして値を設定."""
    keys = path.split(".")
    node = store
    for key in keys[:-1]:
        node = node.setdefault(key, {})
    node[keys[-1]] = value


# ---------------------------------------------------------------------------
# Build — BUILDS 宣言を処理
# ---------------------------------------------------------------------------


def _extract_one(fp: str, prompt: str, content: str) -> tuple[str, str]:
    """1ファイルのLLM凝縮（スレッドプール用）."""
    result = llm.extract(prompt, content, cache_file=CACHE_FILE)
    return fp, result


def _build_condensed(decl: dict, records: list, pool: ThreadPoolExecutor) -> dict[str, str]:
    """type=condensed: LLM凝縮ターゲットを並列ビルド."""
    targets = decl["targets"]
    result: dict[str, str] = {}
    futures = []

    for record in records:
        fp = record.meta.get("file_path", "")
        if not isinstance(fp, str) or fp not in targets:
            continue

        target = targets[fp]
        if target.get("raw"):
            result[fp] = record.content
            print(f"  RAW {fp} ({len(record.content)} chars)", file=sys.stderr)
        else:
            print(f"  BUILD {fp} ...", file=sys.stderr)
            fut = pool.submit(_extract_one, fp, target["prompt"], record.content)
            futures.append(fut)

    for fut in as_completed(futures):
        fp, content = fut.result()
        result[fp] = content
        print(f"  DONE {fp} ({len(content)} chars)", file=sys.stderr)

    return result


def _extract_fields(fp: str, content: str, fields: dict) -> dict[str, str]:
    """1ファイルの全フィールドをLLM生成（スレッドプール用）."""
    entry: dict[str, str] = {"file_path": fp}
    for field_name, field_def in fields.items():
        entry[field_name] = llm.extract(field_def["prompt"], content, cache_file=CACHE_FILE)
    return entry


def _build_file_map(decl: dict, records: list, pool: ThreadPoolExecutor) -> list[dict[str, str]]:
    """type=file_map: 全ファイルのフィールドを並列LLM生成."""
    fields = decl["fields"]
    futures = {}

    for record in records:
        fp = record.meta.get("file_path", "")
        if not isinstance(fp, str) or not fp:
            continue

        print(f"  FILEMAP {fp} ...", file=sys.stderr)
        fut = pool.submit(_extract_fields, fp, record.content, fields)
        futures[fut] = fp

    file_map: list[dict[str, str]] = []
    for fut in as_completed(futures):
        entry = fut.result()
        file_map.append(entry)
        print(f"  DONE {futures[fut]} ({len(fields)} fields)", file=sys.stderr)

    return file_map


_BUILD_HANDLERS = {
    "condensed": _build_condensed,
    "file_map": _build_file_map,
}


# ---------------------------------------------------------------------------
# Query — QUERIES 宣言を処理
# ---------------------------------------------------------------------------


def _render_condensed(section: dict, store: dict, source_filter: str) -> tuple[list[str], list[str]]:
    """type=condensed セクションをレンダリング."""
    targets = section["targets"]
    data = _store_get(store, section["store_path"])

    parts = []
    sources = []

    for fp in targets:
        if fp not in data:
            continue
        if source_filter and source_filter not in fp:
            continue
        label = targets[fp].get("label", fp)
        parts.append(f"## {label}\n\n{data[fp]}")
        sources.append(fp)

    return parts, sources


def _render_table_filter(section: dict, store: dict) -> list[str]:
    """type=table_filter セクションをレンダリング."""
    records = _store_get(store, section["store_path"])
    if not isinstance(records, list):
        return []

    filtered = [r for r in records if section["filter"](r)]
    if not filtered:
        return []

    lines = [section["format"].format(**r) for r in filtered]
    return [f"## {section['label']}\n\n" + "\n".join(lines)]


_RENDER_HANDLERS = {
    "condensed": _render_condensed,
    "table_filter": _render_table_filter,
}


# ---------------------------------------------------------------------------
# Plugin Contract
# ---------------------------------------------------------------------------


def schema():
    """Declare the query interface."""
    return {
        "description": (
            "konkon db プロジェクトコンテキスト。"
            "view パラメータで取得するコンテキストの種類を指定する。"
        ),
        "params": {
            "view": {
                "type": "string",
                "description": "コンテキストのビュー種別",
                "enum": list(QUERIES.keys()),
                "default": "implementation",
            },
            "source": {
                "type": "string",
                "description": "ソースファイルパスで絞り込み（部分一致）",
            },
        },
        "result": {
            "description": "指定ビューのコンテキスト（凝縮済み Markdown）",
            "metadata_keys": ["view", "sources", "total_sources"],
        },
    }


def build(raw_data: RawDataAccessor) -> None:
    """BUILDS 宣言に従いストアにデータを書き込む."""
    store = _load_store()
    records = list(raw_data)

    with ThreadPoolExecutor(max_workers=MAX_WORKERS) as pool:
        for decl in BUILDS:
            handler = _BUILD_HANDLERS[decl["type"]]
            result = handler(decl, records, pool)
            _store_set(store, decl["store_path"], result)
            print(f"  {decl['store_path']}: {len(result)} entries", file=sys.stderr)

    llm.flush_cache()
    _save_store(store)
    print("\nBuild complete.", file=sys.stderr)


def query(request: QueryRequest) -> QueryResult:
    """QUERIES 宣言に従いストアからレスポンスを組み立てる."""
    view_name = request.params.get("view", "implementation")
    view = QUERIES.get(view_name)
    if not view:
        return QueryResult(
            content=f"未知のビュー: '{view_name}'。利用可能: {', '.join(QUERIES)}"
        )

    store = _load_store()
    source_filter = request.params.get("source", "")

    parts = []
    sources = []

    for section in view["sections"]:
        handler = _RENDER_HANDLERS[section["type"]]
        if section["type"] == "condensed":
            p, s = handler(section, store, source_filter)
            parts.extend(p)
            sources.extend(s)
        else:
            p = handler(section, store)
            parts.extend(p)

    if not parts:
        return QueryResult(
            content=f"'{view_name}' コンテキスト未構築。`konkon build --full` を実行してください。"
        )

    header = f"# {view['title']}\n\n"
    body = "\n\n---\n\n".join(parts)

    return QueryResult(
        content=header + body,
        metadata={"view": view_name, "sources": sources, "total_sources": len(sources)},
    )

"""Example plugin: export all raw records to context.json."""

import json
from pathlib import Path

from konkon.types import RawDataAccessor, QueryRequest, QueryResult


def schema():
    """Declare query interface."""
    return {
        "description": "Full-text search over raw records exported to JSON",
        "params": {
            "limit": {
                "type": "integer",
                "description": "Maximum number of results to return",
                "default": 100,
            },
        },
        "result": {
            "description": "Matching records as JSON array",
            "metadata_keys": ["total"],
        },
    }


def build(raw_data: RawDataAccessor) -> None:
    """Append all raw records to context.json."""
    records = [
        {
            "id": r.id,
            "content": r.content,
            "meta": r.meta,
            "created_at": str(r.created_at),
        }
        for r in raw_data
    ]
    Path("context.json").write_text(json.dumps(records, indent=2, ensure_ascii=False))


def query(request: QueryRequest) -> str | QueryResult:
    """Search context.json for records whose content matches the query."""
    path = Path("context.json")
    if not path.exists():
        return "No context built yet. Run 'konkon build' first."

    records = json.loads(path.read_text())
    matches = [r for r in records if request.query.lower() in r["content"].lower()]

    if not matches:
        return QueryResult(content=f"No records matching '{request.query}'.")

    return QueryResult(
        content=json.dumps(matches, indent=2, ensure_ascii=False),
        metadata={"total": len(matches)},
    )

"""konkon init — Create a konkon project (system-level, no Bounded Context)."""

import sys
import tomllib
from pathlib import Path

import click

from konkon.application import init as app_init


def register(group: click.Group) -> None:
    """Register the init command to the CLI group."""
    group.add_command(init)


@click.command(short_help="Create a konkon project")
@click.argument("directory", default=".", type=click.Path())
@click.option("--force", is_flag=True, help="Overwrite existing plugin file")
@click.option(
    "--plugin",
    default=None,
    help="Plugin template path (relative to DIRECTORY).",
)
def init(directory: str, force: bool, plugin: str | None) -> None:
    """Create a konkon project in the specified directory.

    Generates plugin template and .konkon/ directory.
    Raw DB is NOT created here — it is lazily initialized on first insert.
    """
    try:
        app_init(Path(directory).resolve(), force=force, plugin=plugin)
    except tomllib.TOMLDecodeError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except TypeError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except ValueError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(2)
    except FileExistsError as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(2)
    click.echo(f"Initialized konkon project in {Path(directory).resolve()}", err=True)

"""konkon insert — Append text data to Raw DB (Ingestion Context)."""

import sys
from pathlib import Path

import click

from konkon.application import insert as app_insert
from konkon.core.instance import resolve_project


def register(group: click.Group) -> None:
    """Register the insert command to the CLI group."""
    group.add_command(insert)


def _parse_meta(pairs: tuple[str, ...]) -> dict[str, str] | None:
    """Parse KEY=VALUE pairs into a dict. Returns None if empty."""
    if not pairs:
        return None
    result: dict[str, str] = {}
    for pair in pairs:
        key, _, value = pair.partition("=")
        if not key:
            raise click.BadParameter(f"Invalid meta format: {pair!r}")
        result[key] = value
    return result


@click.command(short_help="Append text data to the Raw DB")
@click.argument("text", required=False, default=None)
@click.option("-m", "--meta", multiple=True, help="Metadata as KEY=VALUE")
@click.pass_context
def insert(ctx: click.Context, text: str | None, meta: tuple[str, ...]) -> None:
    """Append text data to the Raw DB.

    TEXT can be provided as argument or via stdin.
    Delegates to Application Layer Use Case.
    """
    try:
        # Resolve content: argument or stdin
        if text is not None:
            content = text
        elif not sys.stdin.isatty():
            content = sys.stdin.read()
            if not content:
                click.echo("Error: No text provided. Pass TEXT argument or pipe via stdin.", err=True)
                sys.exit(1)
        else:
            click.echo("Error: No text provided. Pass TEXT argument or pipe via stdin.", err=True)
            sys.exit(1)

        # Resolve project root
        project_dir = ctx.obj.get("project_dir") if ctx.obj else None
        start = Path(project_dir) if project_dir else None
        project_root = resolve_project(start)

        # Parse metadata
        meta_dict = _parse_meta(meta)

        # Delegate to Application Layer
        record = app_insert(content, meta_dict, project_root)
        click.echo(record.id)
    except FileNotFoundError as e:
        click.echo(str(e), err=True)
        sys.exit(1)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)

"""konkon raw — Raw DB inspection commands (debug / operations)."""

import json
import sys
from pathlib import Path

import click

from konkon.application import raw_get, raw_list
from konkon.core.instance import resolve_project


def register(group: click.Group) -> None:
    """Register the raw command group to the CLI group."""
    group.add_command(raw)


@click.group(short_help="Inspect Raw DB records (debug)")
@click.pass_context
def raw(ctx: click.Context) -> None:
    """Inspect and manage Raw DB records.

    \b
    Subcommands:
      list   List recent raw records
      get    Get a single raw record by ID
    """
    pass


@raw.command("list", short_help="List recent raw records")
@click.option(
    "--limit",
    type=click.IntRange(min=0),
    default=20,
    show_default=True,
    help="Maximum number of records to display.",
)
@click.option(
    "--format",
    "fmt",
    type=click.Choice(["text", "json"]),
    default=None,
    help="Output format (default: auto-detect from TTY).",
)
@click.pass_context
def list_cmd(ctx: click.Context, limit: int, fmt: str | None) -> None:
    """List recent raw records (newest first).

    \b
    Text mode shows a truncated table; JSON mode outputs full records
    as JSON Lines (one JSON object per line).
    """
    try:
        project_dir = ctx.obj.get("project_dir") if ctx.obj else None
        start = Path(project_dir) if project_dir else None
        project_root = resolve_project(start)
    except FileNotFoundError as e:
        click.echo(str(e), err=True)
        sys.exit(3)

    try:
        records = raw_list(project_root, limit=limit)
    except RuntimeError as e:
        # Schema version mismatch etc. — configuration error
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)

    if not records:
        return

    # Resolve format: explicit > TTY detection
    if fmt is None:
        fmt = "text" if sys.stdout.isatty() else "json"

    if fmt == "json":
        for r in records:
            obj = {
                "id": r.id,
                "created_at": r.created_at.strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z",
                "updated_at": (r.updated_at or r.created_at).strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z",
                "content": r.content,
                "meta": dict(r.meta),
            }
            click.echo(json.dumps(obj, ensure_ascii=False))
    else:
        _print_table(records)


@raw.command("get", short_help="Get a single raw record by ID")
@click.argument("record_id", metavar="ID")
@click.option(
    "--format",
    "fmt",
    type=click.Choice(["text", "json"]),
    default=None,
    help="Output format (default: auto-detect from TTY).",
)
@click.pass_context
def get_cmd(ctx: click.Context, record_id: str, fmt: str | None) -> None:
    """Get a single raw record by ID.

    \b
    Text mode shows the full record details;
    JSON mode outputs the record as a single JSON object.
    """
    try:
        project_dir = ctx.obj.get("project_dir") if ctx.obj else None
        start = Path(project_dir) if project_dir else None
        project_root = resolve_project(start)
    except FileNotFoundError as e:
        click.echo(str(e), err=True)
        sys.exit(3)

    try:
        record = raw_get(project_root, record_id)
    except RuntimeError as e:
        # Schema version mismatch etc. — configuration error
        click.echo(f"Error: {e}", err=True)
        sys.exit(3)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)

    if record is None:
        click.echo(f"Error: Record not found: {record_id}", err=True)
        sys.exit(1)

    # Resolve format: explicit > TTY detection
    if fmt is None:
        fmt = "text" if sys.stdout.isatty() else "json"

    if fmt == "json":
        obj = {
            "id": record.id,
            "created_at": record.created_at.strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z",
            "updated_at": (record.updated_at or record.created_at).strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z",
            "content": record.content,
            "meta": dict(record.meta),
        }
        click.echo(json.dumps(obj, ensure_ascii=False))
    else:
        created = record.created_at.strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z"
        updated = (record.updated_at or record.created_at).strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z"
        meta_str = json.dumps(dict(record.meta), ensure_ascii=False) if record.meta else "{}"
        click.echo(f"ID:         {record.id}")
        click.echo(f"Created:    {created}")
        click.echo(f"Updated:    {updated}")
        click.echo(f"Content:    {record.content}")
        click.echo(f"Meta:       {meta_str}")


def _truncate(s: str, length: int = 50) -> str:
    """Truncate string to *length* chars, appending '...' if needed."""
    if len(s) <= length:
        return s
    return s[: length - 3] + "..."


def _print_table(records: list) -> None:
    """Print records as a human-readable table to stdout."""
    # Header
    id_w, ts_w, content_w = 36, 27, 50
    header = f"{'ID':<{id_w}}  {'CREATED_AT':<{ts_w}}  {'UPDATED_AT':<{ts_w}}  {'CONTENT'}"
    click.echo(header)
    click.echo("-" * len(header))

    for r in records:
        created = r.created_at.strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z"
        updated = (r.updated_at or r.created_at).strftime("%Y-%m-%dT%H:%M:%S.%f") + "Z"
        content = _truncate(r.content, content_w)
        click.echo(f"{r.id:<{id_w}}  {created:<{ts_w}}  {updated:<{ts_w}}  {content}")

"""konkon search — Run query() from konkon.py (Transformation Context)."""

import sys
from pathlib import Path

import click

from konkon.application import search as app_search
from konkon.core.instance import resolve_project
from konkon.core.models import QueryResult


def register(group: click.Group) -> None:
    """Register the search command to the CLI group."""
    group.add_command(search)


def _parse_param(
    _ctx: click.Context, _param: click.Parameter, value: tuple[str, ...]
) -> dict[str, str]:
    """Parse KEY=VALUE pairs into a dict."""
    result: dict[str, str] = {}
    for item in value:
        if "=" not in item:
            raise click.BadParameter(f"expected KEY=VALUE, got {item!r}")
        key, val = item.split("=", 1)
        result[key] = val
    return result


@click.command(short_help="Search context via query() in konkon.py")
@click.argument("query")
@click.option(
    "-p",
    "--param",
    "params",
    multiple=True,
    callback=_parse_param,
    expose_value=True,
    help="Plugin parameter as KEY=VALUE (repeatable).",
)
@click.pass_context
def search(ctx: click.Context, query: str, params: dict[str, str]) -> None:
    """Run query() in konkon.py and output results.

    Delegates to Application Layer Use Case.
    """
    try:
        project_dir = ctx.obj.get("project_dir") if ctx.obj else None
        start = Path(project_dir) if project_dir else None
        project_root = resolve_project(start)
        result = app_search(
            project_root,
            query,
            params=params or None,
        )

        if isinstance(result, QueryResult):
            click.echo(result.content)
        else:
            click.echo(result)
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        sys.exit(1)

"""Tests for cli/search.py — konkon search command (Step 10)."""

from pathlib import Path

from click.testing import CliRunner

from konkon.cli import main


def _init_project(runner: CliRunner, path: Path) -> None:
    """Helper: initialize a konkon project."""
    runner.invoke(main, ["init", str(path)])


def _write_plugin(path: Path, code: str) -> None:
    """Helper: overwrite konkon.py with custom plugin code."""
    (path / "konkon.py").write_text(code)


class TestSearchCommand:
    """konkon search QUERY — CLI integration tests."""

    def test_search_returns_result_on_stdout(self, tmp_path: Path):
        """konkon search 'hello' with valid plugin → exit 0, result on stdout."""
        runner = CliRunner()
        _init_project(runner, tmp_path)
        _write_plugin(tmp_path, """\
def schema():
    return {"description": "test", "params": {}}

def build(raw_data):
    pass

def query(request):
    return "found: " + request.query
""")
        result = runner.invoke(main, ["-C", str(tmp_path), "search", "hello"])
        assert result.exit_code == 0
        assert "found: hello" in result.output

    def test_search_without_init_exit_1(self, tmp_path: Path):
        """konkon search without project init → exit 1."""
        runner = CliRunner()
        result = runner.invoke(main, ["-C", str(tmp_path), "search", "hello"])
        assert result.exit_code == 1

    def test_search_no_query_arg_exit_2(self, tmp_path: Path):
        """konkon search with no QUERY argument → exit 2 (click usage error)."""
        runner = CliRunner()
        _init_project(runner, tmp_path)
        result = runner.invoke(main, ["-C", str(tmp_path), "search"])
        assert result.exit_code == 2

    def test_search_query_result_outputs_content(self, tmp_path: Path):
        """Plugin returning QueryResult → content field printed to stdout."""
        runner = CliRunner()
        _init_project(runner, tmp_path)
        _write_plugin(tmp_path, """\
from konkon.core.models import QueryResult

def schema():
    return {"description": "test", "params": {}}

def schema():
    return {"description": "test", "params": {}}

def build(raw_data):
    pass

def query(request):
    return QueryResult(content="the answer", metadata={"score": 0.9})
""")
        result = runner.invoke(main, ["-C", str(tmp_path), "search", "test"])
        assert result.exit_code == 0
        assert "the answer" in result.output

    def test_search_with_param_option(self, tmp_path: Path):
        """konkon search -p limit=5 passes params to plugin."""
        runner = CliRunner()
        _init_project(runner, tmp_path)
        _write_plugin(tmp_path, """\
import json

def schema():
    return {"description": "test", "params": {"limit": {"type": "integer"}}}

def build(raw_data):
    pass

def query(request):
    return json.dumps(dict(request.params))
""")
        result = runner.invoke(
            main, ["-C", str(tmp_path), "search", "-p", "limit=5", "hello"]
        )
        assert result.exit_code == 0
        assert '"limit": "5"' in result.output

    def test_search_with_multiple_params(self, tmp_path: Path):
        """konkon search -p k1=v1 -p k2=v2 passes all params."""
        runner = CliRunner()
        _init_project(runner, tmp_path)
        _write_plugin(tmp_path, """\
import json

def schema():
    return {"description": "test", "params": {}}

def build(raw_data):
    pass

def query(request):
    return json.dumps(dict(request.params), sort_keys=True)
""")
        result = runner.invoke(
